package main

import (
	"fmt"
	"os/exec"
)

func ConvertImage(inputFile string, outputFile string, format string) error {
	cmd := exec.Command("convert", inputFile, "-format", format, outputFile)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return fmt.Errorf("Error converting image: %s\nOutput: %s", err, output)
	}
	return nil
}

func main() {
	inputFile := "input.jpg"
	outputFile := "output.png"
	format := "png"

	err := ConvertImage(inputFile, outputFile, format)
	if err != nil {
		fmt.Println(err)
	}
}